content.content:
/* 宋代美学配色
   宣纸: #F5F0E8   木色: #8B4513   青瓷: #5B7F5B
   暖金: #C4956A   墨色: #3C2415   纸边: #D4C5A9
*/

QMainWindow, QDialog {
    background-color: #F5F0E8;
}

QLabel {
    color: #3C2415;
    font-family: "SimSun", "宋体", serif;
    font-size: 13px;
}

QPushButton {
    background-color: #C4956A;
    color: #3C2415;
    border: 1px solid #8B4513;
    border-radius: 5px;
    padding: 8px 16px;
    font-family: "SimSun", "宋体", serif;
    font-size: 13px;
    min-height: 28px;
}

QPushButton:hover {
    background-color: #D4A574;
    border-color: #6B3410;
}

QPushButton:pressed {
    background-color: #A07850;
}

QPushButton#fillButton {
    background-color: #5B7F5B;
    color: #FFF8EE;
    font-size: 20px;
    font-weight: bold;
    font-family: "KaiTi", "楷体", serif;
    min-width: 80px;
    min-height: 55px;
    border-radius: 8px;
    border: 2px solid #3D5C3D;
}

QPushButton#fillButton:hover {
    background-color: #6B9F6B;
}

QPushButton#importBtn {
    background-color: #8B6F5B;
    color: #FFF8EE;
    font-size: 12px;
    padding: 6px 12px;
    min-height: 24px;
}

QPushButton#importBtn:hover {
    background-color: #A0836D;
}

QPushButton#clearBtn {
    background-color: #B85C5C;
    color: #FFF8EE;
}

QPushButton#clearBtn:hover {
    background-color: #D06B6B;
}

QPushButton#favBtn {
    background-color: #6B7F9F;
    color: #FFF8EE;
}

QPushButton#favBtn:hover {
    background-color: #7B8FAF;
}

QPushButton#smallBtn {
    font-size: 11px;
    padding: 3px 8px;
    min-height: 20px;
    background-color: #D4C5A9;
    color: #3C2415;
}

QPushButton#smallBtn:hover {
    background-color: #E0D4B8;
}

